    ('student02', SHA2('123456', 256), 'USER', 'ACTIVE'),
    ('student03', SHA2('123456', 256), 'USER', 'ACTIVE'),
    ('student04', SHA2('123456', 256), 'USER', 'ACTIVE'),
    ('student05', SHA2('123456', 256), 'USER', 'ACTIVE'),
