    ('student07', SHA2('123456', 256), 'USER', 'ACTIVE'),
    ('student08', SHA2('123456', 256), 'USER', 'ACTIVE'),
    ('student09', SHA2('123456', 256), 'USER', 'ACTIVE'),
    ('student10', SHA2('123456', 256), 'USER', 'ACTIVE')
ON DUPLICATE KEY UPDATE
