INSERT INTO orders (
    order_no,
    user_id,
    activity_id,
    product_id,
    product_title_snapshot,
    purchase_price_cents,
    quantity,
    total_amount_cents,
    status
)
SELECT
    'ORD-SEED-0001',
    u.id,
    a.id,
    p.id,
    p.title,
    a.flash_price_cents,
    1,
    a.flash_price_cents,
    'CREATED'
FROM users AS u
JOIN flash_sale_activities AS a
    ON a.activity_no = 'ACT-HEADSET-001'
JOIN products AS p
    ON p.id = a.product_id
WHERE u.username = 'student03'
ON DUPLICATE KEY UPDATE
    order_no = VALUES(order_no);

INSERT INTO inventory_logs (
    activity_id,
    order_id,
    change_amount,
    stock_after,
    reason
)
SELECT
    o.activity_id,
    o.id,
    -1,
    0,
    'FLASH_SALE_DEDUCT'
FROM orders AS o
WHERE o.order_no = 'ORD-SEED-0001'
ON DUPLICATE KEY UPDATE
    stock_after = VALUES(stock_after);

COMMIT;
